        return Ok(());
    }

    if cloud != cloud_target {
        let content = std::fs::read_to_string(&rbrd)
            .map_err(|e| format!("rbtdrp: read {}: {}", rbrd.display(), e))?;
        let new_content = rbtdrp_replace_env_fields(
            &content,
